class TBrowserProxy:
    def __init__(self, host="127.0.0.1", port=8888):
        self.host = host
        self.port = port
        self.session = None
        self.total_requests = 0
        self.blocked_trackers = 0
        self.bytes_transferred = 0

        # Trackers and ad domains list to filter
        self.blocked_domains = [
            "doubleclick.net",
            "google-analytics.com",
            "analytics.google.com",
            "facebook.net",
            "adnxs.com",
            "amazon-adsystem.com",
            "scorecardresearch.com",
            "quantserve.com",
            "optimizely.com",
            "hotjar.com"
        ]

    def _should_block(self, url: str) -> bool:
        """Determines if a target URL contains an ad or tracker domain."""
        parsed = urllib.parse.urlparse(url)
        netloc = parsed.netloc.lower()
        for domain in self.blocked_domains:
            if domain in netloc:
                return True
        return False

    async def handle_request(self, request: web.Request):
        """Processes and proxies incoming HTTP requests or serves the Console Dashboard."""
        self.total_requests += 1

        # Check if local dashboard page request
        url_str = str(request.url)
        path = request.path

        # If it's a standard root access to the proxy directly
        if path == "/" and not request.query_string and not url_str.startswith("http://http"):
            return web.Response(text=self.get_console_html(), content_type="text/html")

        if path == "/api/stats":
            stats = {
                "total_requests": self.total_requests,
                "blocked_trackers": self.blocked_trackers,
                "bytes_transferred": self.bytes_transferred,
                "status": "Running"
            }
            return web.json_response(stats)

        # Target URL logic for HTTP Proxy behavior
        target_url = request.query.get("url")
        if not target_url:
            # Fallback check for absolute URLs sent directly via web proxy request headers
            if url_str.startswith("http://") and not ("127.0.0.1" in url_str or "localhost" in url_str):
                target_url = url_str
            else:
                return web.Response(
                    text=self.get_console_html(), 
                    content_type="text/html"
                )

        # Verify blocklist
        if self._should_block(target_url):
            self.blocked_trackers += 1
            logging.warning(f"Blocked malicious tracker/ad request: {target_url}")
            return web.Response(
                text="Blocked by RGAI T-Browser Ternary Filter.", 
                status=403
            )

        # Proxy the request
        try:
            headers = {k: v for k, v in request.headers.items() if k.lower() not in ["host", "content-length"]}
            data = await request.read()

            async with self.session.request(
                method=request.method,
                url=target_url,
                headers=headers,
                data=data if data else None,
                allow_redirects=False
            ) as resp:
                body = await resp.read()
                self.bytes_transferred += len(body)

                # Forward response back to the client
                resp_headers = {k: v for k, v in resp.headers.items() if k.lower() not in ["content-encoding", "transfer-encoding"]}
                return web.Response(
                    body=body,
                    status=resp.status,
                    headers=resp_headers
                )
        except Exception as e:
            logging.error(f"Proxy request failed for {target_url}: {e}")
            return web.Response(
                text=f"T-Browser Proxy Error: Failed to reach remote host. Details: {e}",
                status=502
            )

